import { execution } from "@dynatrace-sdk/automation-utils";

export default async function ({ executionId }) {
  const exe = await execution();
  const event = exe.params.event ?? {};

  const getFirstValue = (key: string) => {
    const value = event[key];
    return Array.isArray(value) ? value.find(v => v != null) : value;
  };

  const nowInUTC = Date.now();

  // Prior step output (step id: create_issue)
  const createIssueOutput = await exe.result("create_issue");
  console.log("createIssueOutput:", JSON.stringify(createIssueOutput, null, 2));
  const issue = createIssueOutput.issue ?? createIssueOutput;

  // Use browser URL for annotation link
  const issueUrl = issue.html_url ?? issue.url ?? "";
  console.log("url: " + issueUrl)

  return {
    eventType: 'CUSTOM_ANNOTATION',
    title: 'Created GitHub issue',
    startTime: nowInUTC,
    endTime: nowInUTC,
    properties: {
      'annotation.source': 'GitHub',
      'annotation.id': '' + Math.random(),
      'annotation.url': issueUrl,      
      'annotation.problem_ids': getFirstValue("event.id"),
      'dt.event.description': 'Arc store agentic triage workflow kicked off. Automatic GitHub issue created:',
    }
  };
}

