import { execution } from "@dynatrace-sdk/automation-utils";

export default async function ({ executionId }) {
  const exe = await execution(executionId);
  const dql = await exe.result("dql_query_get_logs");
  const event = exe.params.event ?? {};

  const getFirstValue = (key: string) => {
    const value = event[key];
    return Array.isArray(value) ? value.find(v => v != null) : value;
  };

  const records = Array.isArray(dql?.records) ? dql.records : [];

  const lines = records.map((r, i) => {
    const ts = r?.timestamp ?? "unknown-time";
    const pod = r?.["k8s.pod.name"] ?? "unknown-pod";
    const lvl = r?.loglevel ?? "UNKNOWN";
    const msg = String(r?.content ?? "").trim();
    return `${i + 1}. [${ts}] [${lvl}] [${pod}]\n${msg}`;
  });

  const stackText = lines.length ? lines.join("\n\n") : "No matching error logs found.";

  const issueBody =
`## Issue detected in the Arc Store

Problem: ${getFirstValue("display_id") ?? "unknown"}
Name: ${getFirstValue("event.name") ?? "unknown"}
Entity: ${getFirstValue("affected_entity_names") ?? getFirstValue("dt.source_entity") ?? "unknown"}

### Error logs / stack trace
${stackText}
`;

 // GitHub issue body max is large, but trim to be safe
 return issueBody.slice(0, 60000);
}
